    69→		name:     name,
    70→		clock:    clock,
    71→		lastTime: clock.Now(),
    72→	}
    73→}
    74→
    75→func (igr *integrator) Set(x float64) {
    76→	igr.Lock()
    77→	igr.setLocked(x)
    78→	igr.Unlock()
    79→}
