   170→		ElapsedSeconds: igr.ElapsedSeconds - ogr.ElapsedSeconds,
   171→		IntegralX:      igr.IntegralX - ogr.IntegralX,
   172→		IntegralXX:     igr.IntegralXX - ogr.IntegralXX,
