   181→	avg := igr.IntegralX / igr.ElapsedSeconds
   182→	// standard deviation is sqrt( average( (x - xbar)^2 ) )
   183→	// = sqrt( Integral( x^2 + xbar^2 -2*x*xbar dt ) / Duration )
