   185→	// = sqrt( Integral(x^2 dt)/Duration - xbar^2 )
   186→	variance := igr.IntegralXX/igr.ElapsedSeconds - avg*avg
   187→	if variance >= 0 {
   188→		return avg, math.Sqrt(variance)
   189→	}
   190→	return avg, math.NaN()
   191→}
